func getActionURL(p *models.Product) string {
	if p.ID == 0 {
		return "/products"
	}
	return fmt.Sprintf("/products/%d", p.ID)
}

func getStockColor(qty int) string {
	if qty > 0 {
		return "text-green-600"
	}
	return "text-red-600"
}

