	return templ.ComponentScript{
		Name: `__templ_DeleteProduct_9ddd`,
		Function: `function __templ_DeleteProduct_9ddd(id){if (confirm('Möchten Sie dieses Produkt wirklich löschen?')) {
		fetch('/products/' + str(id) + '/delete', {
			method: 'POST',
		}).then(() => {
			window.location.href = '/products';
		});
	}
}`,
		Call:       templ.SafeScript(`__templ_DeleteProduct_9ddd`, id),
		CallInline: templ.SafeScriptInline(`__templ_DeleteProduct_9ddd`, id),
	}
